import React from 'react';
import { useDispatch, useSelector } from 'react-redux';
import './App.css';
import { removeLastTodo, addTodo } from './store/toolkitSlice';

function App() {
  const [value, setValue] = useSelector('')
  const todos = useSelector(state => state.toolkit.todos)
  const dispatch = useDispatch()

  const handleSubmit = (e) => {
    if (e.code === 'Enter' && value.trim()) {
      addTodo(value.trim())
      set
    }
  }

  return (
    <div className="App">
      <input type='text' value={value} onChange={(e) => setValue(e.target.value)} onKeyDown={handleSubmit}/>
      <button onClick={() => dispatch(addTodo())}>add Todo</button>
      <button onClick={() => dispatch(removeLastTodo())}>remove Todo</button>
      <div>
        {todos.map(todo => 
          <div key={todo}>{todo}</div>
        )}
      </div>
    </div>
  );
}

export default App;
